mapper.select:
SELECT dp.kor_co_nm as bank_name, dp.fin_prdt_nm as product_name, dp.etc_note as etc_note, opt.max_save_trm, opt.max_intr_rate, opt.max_intr_rate2 FROM deposit_product dp LEFT JOIN opt ON dp.fin_prdt_cd = opt.fin_prdt_cd AND opt.rn = 1 WHERE 1=1
AND opt.max_intr_rate >= #{minRate}
AND opt.max_intr_rate <= #{maxRate}
ORDER BY opt.max_intr_rate DESC, dp.kor_co_nm
